const [w, setW] = useState(0);
const r = useRef<HTMLDivElement>(null);
useLayoutEffect(() => {
  if (!r.current) return;
  const o = new ResizeObserver(([e]) => setW(e.contentRect.width));
  o.observe(r.current);
  return () => o.disconnect();
}, []);

export function JsonDebug({ d }: { d: unknown }) {
  return <pre>{JSON.stringify(d, null, 2)}</pre>;
}
